module CartesianDerivs
using StaticArrays

xC(x::MVector{3, Float64})::Float64 = cos(x[3])*x[1]*sin(x[2])

dxC(x::MVector{3, Float64}, dx::MVector{3, Float64})::Float64 = cos(x[3])*sin(x[2])*dx[1] + x[1]*(cos(x[2])*cos(x[3])*dx[2] - sin(x[2])*sin(x[3])*dx[3])

