d3xC(x::MVector{3, Float64}, dx::MVector{3, Float64}, d2x::MVector{3, Float64}, d3x::MVector{3, Float64})::Float64 = 3*(cos(x[3])*dx[1] - x[1]*sin(x[3])*dx[3])*(-(sin(x[2])*dx[2]^2) + cos(x[2])*d2x[2]) - 3*cos(x[2])*dx[2]*(2*sin(x[3])*dx[1]*dx[3] - cos(x[3])*d2x[1] + x[1]*(cos(x[3])*dx[3]^2 + sin(x[3])*d2x[3])) + cos(x[3])*x[1]*(-(cos(x[2])*dx[2]^3) - 3*sin(x[2])*dx[2]*d2x[2] + cos(x[2])*d3x[2]) + sin(x[2])*(-3*sin(x[3])*dx[3]*d2x[1] - 3*dx[1]*(cos(x[3])*dx[3]^2 + sin(x[3])*d2x[3]) + cos(x[3])*d3x[1] + x[1]*(sin(x[3])*dx[3]^3 - 3*cos(x[3])*dx[3]*d2x[3] - sin(x[3])*d3x[3]))

